        if (this%verbose) write (*, '("[tb_dev] Created new buffer")')
    ELSE
        if (this%verbose) write (*, '("[tb_dev] Locked buffer", I4)') good_one_idx
    END IF
    !
    if (this%verbose) &
         write (*, '("[tb_dev] Currently allocated ", (es12.2), " Mbytes")') REAL(tsz)/1048576 ! 1024/1024
    !
